 "user", "aggregation": "none", "description": "", "ui_settings": "", "guid_formula": "", "default_value": null, "lock_aggregation": false, "value_constraint": null, "initial_data_type": "string", "has_auto_aggregation": false}], "schema_version": "1", "source_avatars": [{"id": "47043f10-2d45-11f1-af07-95e51af44142", "title": "╨а╨╡╨╣╤Б╤Л ╨┐╨╛ ╨║╨╗╨░╤Б╤Б╨░╨╝ (╨б╨╡╨╗╨╡╨║╤В╨╛╤А ╨Э╨░╨┐╤А-╨╡)", "valid": true, "is_root": true, "source_id": "47043f11-2d45-11f1-af07-95e51af44142", "managed_by": "user"}], "avatar_relations": [], "component_errors": {"items": []}, "template_enabled": true, "result_schema_aux": {"inter_dependencies": {"deps": []}}, "obligatory_filters": [], "source_collections": [{"id": "47043f11-2d45-11f1-af07-95e51af44142", "title": "╨а╨╡╨╣╤Б╤Л ╨┐╨╛ ╨║╨╗╨░╤Б╤Б╨░╨╝ (╨б╨╡╨╗╨╡╨║╤В╨╛╤А ╨Э╨░╨┐╤А-╨╡)", "valid": true, "origin": {"parameters": {"subsql": "SELECT DISTINCT\r\n    m1.ap1 + ''-'' + m2.ap2 AS mrshr,\r\n    r.nr                  AS flight_no\r\nFROM spp_reis r\r\nJOIN spp_mrshr m1 ON m1.id_reis = r.id\r\nJOIN spp_mrshr m2 ON m2.id_reis = r.id AND m1.nu <= m2.nu\r\nWHERE r.nr IN ({{nrs}})\r\n  AND YEAR(r.dvm) = YEAR(CONVERT(date, CASE\r\n      WHEN {{ds}} LIKE ''__interval_%'' THEN SUBSTRING({{ds}}, 12, 10)\r\n      ELSE {{ds}}\r\n  END))\r\n  AND MONTH(r.dvm) = MONTH(CONVERT(date, CASE\r\n      WHEN {{ds}} LIKE ''__interval_%'' THEN SUBSTRING({{ds}}, 12, 10)\r\n      ELSE {{ds}}\r\n  END))"}, "raw_schema": [{"name": "mrshr", "type": "string", "title": "mrshr", "nullable": false, "description": "", "native_type": {"name": "varchar", "nullable": false, "native_type_class_name": "common_native_type"}, "lock_aggregation": false, "has_auto_aggregation": false}, {"name": "flight_no", "type": "string", "title": "flight_no", "nullable": false, "description": "", "native_type": {"name": "varchar", "nullable": false, "native_type_class_name": "common_native_type"}, "lock_aggregation": false, "has_auto_aggregation": false}], "created_from": "MSSQL_SUBSELECT", "connection_id": "qsz0o3f3namsa"}, "sample": null, "managed_by": "user", "materialization": null}], "data_export_forbidden": false, "load_preview_by_default": true}', '{"created_via": "user"}', 'uid:1', '2026-04-01 11:10:04.478632+00', 'uid:1', '2026-04-01 11:10:04.478632+00', 2183452359005308376, 2183027695481259387, '{"47043f11-2d45-11f1-af07-95e51af44142": "qsz0o3f3namsa"}', '{"description": ""}') ON CONFLICT DO NOTHING;
